'use client'

import {
  cn,
  DismissableLayer,
  Presence,
  useAnchorPosition,
  useRovingFocus,
  useSignal,
  useSignals,
} from '@cascivo/core'
import { useId, useRef } from 'react'
import type { CSSProperties, KeyboardEvent, ReactNode } from 'react'
import styles from './menubar.module.css'

export interface MenubarItem {
  id: string
  label: ReactNode
  onSelect?: () => void
  disabled?: boolean
}

export interface MenubarMenu {
  id: string
  label: ReactNode
  items: MenubarItem[]
}

export interface MenubarProps {
  menus: MenubarMenu[]
  'aria-label': string
  className?: string
}

export function Menubar({ menus, 'aria-label': ariaLabel, className }: MenubarProps) {
  useSignals()
  const baseId = useId()
  const openId = useSignal<string | null>(null)
  const roving = useRovingFocus({ orientation: 'horizontal', loop: true })

  return (
    <div role="menubar" aria-label={ariaLabel} className={cn(styles['menubar'], className)}>
      {menus.map((menu, index) => (
        <MenubarTrigger
          key={menu.id}
          menu={menu}
          index={index}
          baseId={baseId}
          openId={openId}
          itemProps={roving.getItemProps(index)}
        />
      ))}
    </div>
  )
}

interface MenubarTriggerProps {
  menu: MenubarMenu
  index: number
  baseId: string
  openId: ReturnType<typeof useSignal<string | null>>
  itemProps: ReturnType<ReturnType<typeof useRovingFocus>['getItemProps']>
}

function MenubarTrigger({ menu, baseId, openId, itemProps }: MenubarTriggerProps) {
  useSignals()
  const triggerRef = useRef<HTMLButtonElement>(null)
  const floatingRef = useRef<HTMLDivElement>(null)
  const isOpen = openId.value === menu.id
  const menuId = `${baseId}-menu-${menu.id}`

  const { anchorStyle, floatingStyle } = useAnchorPosition({
    anchorRef: triggerRef,
    floatingRef,
    placement: 'bottom-start',
    enabled: isOpen,
  })

  const focusFirstItem = (): void => {
    const first = floatingRef.current?.querySelector<HTMLElement>(
      '[role="menuitem"]:not([aria-disabled="true"])',
    )
    first?.focus()
  }

  const handleKeyDown = (event: KeyboardEvent<HTMLButtonElement>): void => {
    itemProps.onKeyDown(event)
    if (event.defaultPrevented) return
    if (event.key === 'ArrowDown' || event.key === 'Enter' || event.key === ' ') {
      event.preventDefault()
      openId.value = menu.id
      requestAnimationFrame(focusFirstItem)
    } else if (event.key === 'Escape') {
      openId.value = null
    }
  }

  const { ref: rovingRef, onKeyDown: _onKeyDown, ...rovingRest } = itemProps

  return (
    <>
      <button
        ref={(el) => {
          triggerRef.current = el
          rovingRef(el)
        }}
        type="button"
        role="menuitem"
        aria-haspopup="menu"
        aria-expanded={isOpen}
        aria-controls={menuId}
        data-state={isOpen ? 'open' : 'closed'}
        className={styles['trigger']}
        style={anchorStyle}
        onClick={() => {
          openId.value = isOpen ? null : menu.id
        }}
        onKeyDown={handleKeyDown}
        {...rovingRest}
      >
        {menu.label}
      </button>
      <Presence present={isOpen}>
        <MenubarPanel
          menu={menu}
          menuId={menuId}
          floatingRef={floatingRef}
          floatingStyle={floatingStyle}
          onClose={() => {
            openId.value = null
            triggerRef.current?.focus()
          }}
        />
      </Presence>
    </>
  )
}

interface MenubarPanelProps {
  menu: MenubarMenu
  menuId: string
  floatingRef: React.RefObject<HTMLDivElement | null>
  floatingStyle: CSSProperties
  onClose: () => void
}

function MenubarPanel({ menu, menuId, floatingRef, floatingStyle, onClose }: MenubarPanelProps) {
  const handleItemKeyDown = (event: KeyboardEvent<HTMLDivElement>): void => {
    const items = Array.from(
      floatingRef.current?.querySelectorAll<HTMLElement>(
        '[role="menuitem"]:not([aria-disabled="true"])',
      ) ?? [],
    )
    if (items.length === 0) return
    const current = items.indexOf(event.currentTarget)
    if (event.key === 'ArrowDown') {
      event.preventDefault()
      items[(current + 1) % items.length]?.focus()
    } else if (event.key === 'ArrowUp') {
      event.preventDefault()
      items[(current - 1 + items.length) % items.length]?.focus()
    } else if (event.key === 'Home') {
      event.preventDefault()
      items[0]?.focus()
    } else if (event.key === 'End') {
      event.preventDefault()
      items[items.length - 1]?.focus()
    }
  }

  return (
    <DismissableLayer onDismiss={onClose}>
      <div
        ref={floatingRef}
        id={menuId}
        role="menu"
        aria-label={typeof menu.label === 'string' ? menu.label : undefined}
        className={styles['panel']}
        style={floatingStyle}
      >
        {menu.items.map((item) => (
          <div
            key={item.id}
            role="menuitem"
            tabIndex={-1}
            aria-disabled={item.disabled}
            className={styles['item']}
            onClick={() => {
              if (item.disabled) return
              item.onSelect?.()
              onClose()
            }}
            onKeyDown={(event) => {
              if (item.disabled) return
              if (event.key === 'Enter' || event.key === ' ') {
                event.preventDefault()
                item.onSelect?.()
                onClose()
              } else {
                handleItemKeyDown(event)
              }
            }}
          >
            {item.label}
          </div>
        ))}
      </div>
    </DismissableLayer>
  )
}

@layer cascivo.component {
  .menubar {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    padding: var(--cascivo-space-1);
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-control);
  }

  .trigger {
    display: inline-flex;
    align-items: center;
    padding-block: var(--cascivo-space-1);
    padding-inline: var(--cascivo-space-3);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-item);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    cursor: pointer;

    &:hover,
    &[data-state='open'] {
      background: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: var(--cascivo-focus-ring);
      outline-offset: 2px;
    }
  }

  .panel {
    position: fixed;
    inset: auto;
    margin: 0;
    padding: var(--cascivo-space-1);
    min-width: 10rem;
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-md);

    opacity: 1;
    translate: 0 0;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter);

    @starting-style {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
    }

    &[data-state='closed'] {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
      transition:
        opacity var(--cascivo-motion-exit),
        translate var(--cascivo-motion-exit);
    }
  }

  .item {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    padding-block: var(--cascivo-space-2);
    padding-inline: var(--cascivo-space-3);
    border-radius: var(--cascivo-radius-item);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    cursor: pointer;
    user-select: none;
    outline: none;

    &:hover,
    &:focus-visible {
      background: var(--cascivo-color-bg-subtle);
    }

    &[aria-disabled='true'] {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }
}

@media (prefers-reduced-motion: reduce) {
  .panel {
    transition: none;
  }
}

@media (forced-colors: active) {
  .trigger:focus-visible {
    outline: 2px solid Highlight;
  }
}
